    function renderIndustryDepartments(){
      const industryEl=document.getElementById('industry');
      const root=document.getElementById('industryDepartments');
      if(!industryEl || !root)return;
      const deps=industryDepartmentsMap[industryEl.value] || [];
      if(!industryEl.value){
        root.innerHTML='<div class="department-empty">Выберите отрасль на первой странице — здесь появится список профильных департаментов.</div>';
        return;
      }
      const departmentItems = deps.map(dep => {
        const title=Array.isArray(dep) ? dep[0] : dep;
        const desc=Array.isArray(dep) ? dep[1] : 'Профильный департамент';
        return `
        <label class="check industry-department"><input type="checkbox" name="department" value="${title}"><div><strong>${title}</strong><span>${desc}</span></div></label>
      `;
      }).join('');
      root.innerHTML = `
        <label class="check industry-department department-select-all"><input type="checkbox" id="selectAllDepartments"><div><strong>Выбрать все отделы</strong><span>Отметить все отделы для выбранной отрасли</span></div></label>
        ${departmentItems}
        <div class="department-other"><label for="otherDepartment">Другой отдел</label><input id="otherDepartment" name="otherDepartment" type="text" placeholder="Введите название отдела"></div>
      `;
    }

