    let coreQuestions=[];

    function getActiveIndustryConfig(){
      const industry=document.getElementById('industry')?.value || '';
      return industryQuestionBank[industry] || null;
    }

    function syncCoreQuestions(){
      const cfg=getActiveIndustryConfig();
      coreQuestions = cfg ? cfg.questions : [];
    }

    const form=document.getElementById('form');
    let step=0;


    const dmqSessionKey = `dmq-v28-scale-answers:${location.pathname}`;

    function dmqReadSessionState(){
      try{
        return JSON.parse(sessionStorage.getItem(dmqSessionKey) || '{}') || {};
      }catch(e){
        return {};
      }
    }

    function dmqWriteSessionState(state){
      try{
        sessionStorage.setItem(dmqSessionKey, JSON.stringify(state || {}));
      }catch(e){}
    }

    function dmqSaveScaleSession(range){
      if(!range || !range.name) return;
      const state=dmqReadSessionState();
      state.answers = state.answers || {};
      state.answers[range.name]={
        value:String(range.value),
        touched:range.dataset.touched === '1'
      };
      const industryEl=document.getElementById('industry');
      if(industryEl) state.industry=industryEl.value || '';
      state.updatedAt=new Date().toISOString();
      dmqWriteSessionState(state);
    }

    function dmqSaveAllScaleSession(){
      const state=dmqReadSessionState();
      state.answers = state.answers || {};
      document.querySelectorAll('#coreQuestions input[type=range]').forEach(range=>{
        if(range.name){
          state.answers[range.name]={
            value:String(range.value),
            touched:range.dataset.touched === '1'
          };
        }
      });
      const industryEl=document.getElementById('industry');
      if(industryEl) state.industry=industryEl.value || '';
      state.updatedAt=new Date().toISOString();
      dmqWriteSessionState(state);
    }

    function dmqRestoreIndustrySession(){
      const state=dmqReadSessionState();
      const industryEl=document.getElementById('industry');
      if(industryEl && !industryEl.value && state.industry){
        industryEl.value=state.industry;
      }
    }

    function dmqRestoreScaleSession(){
      const state=dmqReadSessionState();
      const answers=state.answers || {};
      document.querySelectorAll('#coreQuestions input[type=range]').forEach(range=>{
        const saved=answers[range.name];
        if(!saved) return;
        const value=Math.max(Number(range.min || 0), Math.min(Number(range.max || 5), Number(saved.value)));
        if(Number.isFinite(value)) range.value=String(value);
        range.dataset.touched = saved.touched ? '1' : '0';
        updateRangeVisual(range);
      });
    }

