    function val(name){
      const el=form.elements[name];
      if(!el)return'';
      if(el instanceof RadioNodeList){
        const checked=Array.from(el).filter(x=>x.checked).map(x=>x.value);
        if(checked.length>1)return checked;
        return el.value||'';
      }
      return el.type==='checkbox'?(el.checked?el.value:''):(el.value||'')
    }
