    function scores(){
      syncCoreQuestions();
      const sums={},counts={};
      Object.keys(domains).forEach(k=>{sums[k]=0;counts[k]=0});

      // : все 15 вопросов находятся в одном блоке и уже привязаны к доменам.
      // Незатронутый слайдер считается как 0, чтобы незаполненные вопросы снижали итоговый индекс.
      coreQuestions.forEach(q=>{
        sums[q.domain]+=Number(val(q.id)||0);
        counts[q.domain]++;
      });

      const s={};
      Object.keys(domains).forEach(k=>s[k]=counts[k]?+(sums[k]/counts[k]).toFixed(2):0);
      return s;
    }
