      if(s.strategy<2.2)list.push(['Стратегия','Сформировать портфель инициатив и дорожную карту на 6–12 месяцев.']);
      if(s.data>=2.2&&s.tech>=2.2)list.push(['готовность к ИИ зона','Сформировать перечень сценариев применения AI/ML, RPA, OCR и process mining.']);
