      return{meta:{prototype:'sber2b_digital_ai_maturity_page_v2',created_at:new Date().toISOString(),source:'html_mvp',recommendation_model:r.model,model_version:r.model_version},contact:{full_name:val('fullName'),company:val('company'),company_inn:val('companyInn'),company_email:val('companyEmail'),phone:val('phone'),pd_consent:Boolean(val('pdConsent'))},context:{industry:val('industry'),department:(function(){const selected=Array.isArray(val('department'))?val('department'):(val('department')?[val('department')]:[]);const other=(val('otherDepartment')||'').trim();return other?[...selected,other]:selected;})(),other_department:(val('otherDepartment')||'').trim()},scoring:{overall_index_0_5:+o.toFixed(2),overall_index_0_100:Math.round(o/5*100),maturity_level:level(o),domain_scores_0_5:s,industry_average_from_excel:getCurrentIndustryAverage(),industry_score_legacy:industryScore(),industry_domain_scores_legacy:industryDomainScores()},recommendation:{primary_project_type:r.type,priority:r.priority,tree_rule_path:r.rule_path,confidence:r.confidence,model_features:decisionTreeMvp.features,model_thresholds:decisionTreeMvp.thresholds,hypotheses:h.map(x=>({title:x[0],description:x[1]})),recommended_actions:rs.map(x=>({title:x[0],description:x[1]})),recommended_products:productRecommendations(Math.round(o/5*100)).products.map(x=>({product:x.name,probability:x.prob}))},raw_answers:raw}
