    function rangeColor(v){
      return ['#d9e1ec','#8b0000','#d71920','#f36f21','#ffd23f','#1eb43f'][Number(v)] || '#d9e1ec';
    }
    function updateRangeVisual(range){
      const v=Number(range.value || 0);
      const touched=range.dataset.touched==='1';
      const pct=touched ? (v/5)*100 : 0;
      const color=touched ? rangeColor(v) : '#d9e1ec';
      const fill=touched ? `linear-gradient(90deg, ${color} 0%, ${color} ${pct}%, #edf1f7 ${pct}%, #edf1f7 100%)` : 'linear-gradient(90deg,#edf1f7 0%,#edf1f7 100%)';
      range.style.setProperty('--range-color', color);
      range.style.setProperty('--tooltip-left', `${touched ? pct : 0}%`);
      range.style.setProperty('--range-fill', fill);
      range.style.background = fill;
      const row=range.closest('.range-row');
      if(row){
        row.style.setProperty('--range-color', color);
        row.style.setProperty('--tooltip-left', `${touched ? pct : 0}%`);
      }
      const valueEl=document.getElementById(`${range.name}_v`);
      if(valueEl){
        valueEl.textContent=touched ? range.value : '—';
        valueEl.style.setProperty('--range-color', color);
        valueEl.classList.toggle('is-empty', !touched);
      }
      const domain=range.dataset.domain;
      const tip=document.getElementById(range.dataset.tooltip);
      if(tip){
        if(touched){
          const domainName=domains[domain]?.label || '';
          const text=scoreDescriptions[domain]?.[v] || '';
          tip.innerHTML=`<b>${domainName} · ${v}</b><span>${text}</span>`;
        }else{
          tip.textContent='Передвиньте ползунок, чтобы выбрать уровень зрелости';
        }
      }
      const wrap=range.closest('.range-wrap');
      if(wrap){
        wrap.querySelectorAll('.range-tick').forEach((tick,idx)=>{
          tick.classList.toggle('is-active', touched && idx===v);
        });
      }
    }
    function initRangeInteractions(){
      document.querySelectorAll('#coreQuestions input[type=range]').forEach(r=>{
        r.classList.add('maturity-range');
        updateRangeVisual(r);
        const row=r.closest('.range-row');
        if(!r.dataset.bound){
          r.dataset.bound='1';
          r.addEventListener('input',()=>{r.dataset.touched='1';updateRangeVisual(r);dmqSaveScaleSession(r);});
          r.addEventListener('change',()=>{r.dataset.touched='1';updateRangeVisual(r);dmqSaveScaleSession(r);});
          r.addEventListener('pointerdown',()=>{r.dataset.touched='1';updateRangeVisual(r);dmqSaveScaleSession(r);row&&row.classList.add('is-dragging')});
          r.addEventListener('pointerup',()=>row&&row.classList.remove('is-dragging'));
          r.addEventListener('pointercancel',()=>row&&row.classList.remove('is-dragging'));
          r.addEventListener('blur',()=>row&&row.classList.remove('is-dragging'));
        }
      });
    }



    function v28MixColor(a,b,t){
      const ah=parseInt(a.slice(1),16), bh=parseInt(b.slice(1),16);
      const ar=ah>>16, ag=(ah>>8)&255, ab=ah&255;
      const br=bh>>16, bg=(bh>>8)&255, bb=bh&255;
      const rr=Math.round(ar+(br-ar)*t), rg=Math.round(ag+(bg-ag)*t), rb=Math.round(ab+(bb-ab)*t);
      return '#' + ((1<<24) + (rr<<16) + (rg<<8) + rb).toString(16).slice(1);
    }
    function v28ScoreColor(score){
      const s=Math.max(0,Math.min(100,Number(score)||0));
      if(s<35) return v28MixColor('#d71920','#f36f21',s/35);
      if(s<55) return v28MixColor('#f36f21','#ffd23f',(s-35)/20);
      return v28MixColor('#ffd23f','#1eb43f',(s-55)/45);
    }


    function v28ProcessResultText(score){
      if(score < 20){
        return 'Процессы непредсказуемые и неуправляемые. Результат стохастический и заранее не прогнозируется. Риски максимальные, цифровые и ИТ-решения фактически отсутствуют.';
      }
      if(score < 40){
        return 'Процессы слабо контролируются. Результат достигается с трудом, риски затрагивают качество, бюджет и сроки. Используются цифровые инструменты базового уровня.';
      }
      if(score < 60){
        return 'Процессы не всегда регламентированы и часто зависят от исполнителей. Результат достигается в срок, но сохраняются риски для качества и бюджета. Используются коробочные ИТ-системы.';
      }
      if(score < 75){
        return 'Процессы определены для ключевых операций. Результат качественный и достигается в срок, ключевой риск связан с бюджетом. Начинается интеграция смежных ИТ-систем.';
      }
      if(score < 90){
        return 'Процессы измеряются и контролируются. Результат соответствует срокам, бюджету и качеству. Используются интеграция больших данных, аналитика и AI/ML-сценарии.';
      }
      return 'Процессы постоянно совершенствуются. Результат влияет на последующие действия, риски минимальны. ИТ-экосистема управляется на уровне компании или группы компаний.';
    }

    function v28Level(score){
      if(score < 20) return 'Отсутствующий уровень';
      if(score < 40) return 'Начальный уровень';
      if(score < 60) return 'Управляемый уровень';
      if(score < 75) return 'Определяемый уровень';
      if(score < 90) return 'Измеряемый уровень';
      return 'Улучшаемый уровень';
    }
    function v28RenderGauge(score){
      const arc = document.getElementById('v28GaugeArc');
      const knob = document.getElementById('v28GaugeKnob');
      const scoreNode = document.getElementById('v28ScoreValue');
      const levelNode = document.getElementById('v28ScoreLevel');
      const noteNode = document.getElementById('v28ScoreNote');
      const color = v28ScoreColor(score);
      document.documentElement.style.setProperty('--v28-score-color', color);
      if(scoreNode){
        scoreNode.textContent = score;
        scoreNode.style.setProperty('color', color, 'important');
      }
      if(levelNode){
        levelNode.textContent = v28Level(score);
        levelNode.style.setProperty('color', color, 'important');
      }
      if(arc) arc.style.strokeDashoffset = String(100 - score);
      if(knob){
        const angle = Math.PI - (score/100) * Math.PI;
        const cx = 210, cy = 192, r = 154;
        knob.setAttribute('cx', String(cx + Math.cos(angle) * r));
        knob.setAttribute('cy', String(cy - Math.sin(angle) * r));
        knob.setAttribute('stroke', color);
      }
      if(noteNode){
        noteNode.textContent = v28ProcessResultText(score);
      }
    }
    function getCurrentIndustryAverage(){
      const industry=document.getElementById('industry')?.value || '';
      return industryAveragesFromExcel[industry] || null;
    }



    function v28NormalizeDomainAvgTo100(value){
      const n = Number(value);
      if(!Number.isFinite(n)) return 0;
      // Industry benchmark domain averages are stored on a 0–20 scale
      // because the total industry index is 0–100 across 5 domains.
      // The pentagram axes are 0–100 per domain, i.e. 0–500 in total.
      // Convert 0–20 domain values to the same 0–100 axis scale.
      return Math.max(0, Math.min(100, n <= 20 ? n * 5 : n));
    }

    function v28UpdateIndustryBenchmark(s){
      const keys = ['strategy','process','data','tech','competence'];
      const avgCfg = getCurrentIndustryAverage();
      const industrySum = avgCfg ? keys.reduce((sum,k)=>sum + v28NormalizeDomainAvgTo100(avgCfg.domainAvg?.[k]),0) : null;
      const userSum = keys.reduce((sum,k)=>sum + ((Number(s[k]) || 0) / 5 * 100),0);
      const industryNode = document.getElementById('v28BenchmarkIndustry');
      const userNode = document.getElementById('v28BenchmarkUser');
      if(industryNode) industryNode.textContent = industrySum === null ? '—' : String(Math.round(industrySum));
      if(userNode) userNode.textContent = String(Math.round(userSum));
    }

    function v28RenderRadar(s){
      const svg = document.getElementById('v28Radar');
      if(!svg) return;
      svg.setAttribute('viewBox','0 0 1280 820');
      svg.setAttribute('preserveAspectRatio','xMidYMid meet');
      const keys = ['strategy','process','data','tech','competence'];
      const names = {strategy:'Стратегия и управление',process:'Процессы',data:'Данные',tech:'Технологии',competence:'Команда'};
      const icons = {strategy:'fa-chess',process:'fa-gears',data:'fa-database',tech:'fa-microchip',competence:'fa-users'};
      const cx = 640, cy = 405, rr = 285;
      const angle = i => -Math.PI / 2 + i * 2 * Math.PI / keys.length;
      const point = (i, radius) => [cx + Math.cos(angle(i)) * radius, cy + Math.sin(angle(i)) * radius];
      const poly = radius => keys.map((_, i) => point(i, radius).join(',')).join(' ');
      const vals = keys.map(k => Math.round((s[k] || 0) / 5 * 100));
      const avgCfg = getCurrentIndustryAverage();
      const avgVals = keys.map(k => v28NormalizeDomainAvgTo100(avgCfg?.domainAvg?.[k]));
      const avgPts = keys.map((k, i) => point(i, rr * avgVals[i] / 100));
      const avgScore = Math.round(vals.reduce((a,b)=>a+b,0)/vals.length);
      const avgColor = v28ScoreColor(avgScore);
      const pts = keys.map((k, i) => point(i, rr * (s[k] || 0) / 5));
      svg.innerHTML =
        '<defs><linearGradient id="v28RadarStroke" x1="0%" y1="0%" x2="100%" y2="100%"><stop offset="0%" stop-color="#d71920"/><stop offset="50%" stop-color="#ffd23f"/><stop offset="100%" stop-color="#1eb43f"/></linearGradient><radialGradient id="v28RadarFill" cx="50%" cy="50%" r="65%"><stop offset="0%" stop-color="'+avgColor+'" stop-opacity=".14"/><stop offset="70%" stop-color="'+avgColor+'" stop-opacity=".24"/><stop offset="100%" stop-color="'+avgColor+'" stop-opacity=".40"/></radialGradient></defs>' +
        [1,.75,.5,.25].map(m => `<polygon points="${poly(rr*m)}" fill="none" stroke="#d3dbea" stroke-width="1.6"/>`).join('') +
        keys.map((k,i) => { const p = point(i,rr); return `<line x1="${cx}" y1="${cy}" x2="${p[0]}" y2="${p[1]}" stroke="#d3dbea" stroke-width="1.2"/>`; }).join('') +
        (avgCfg ? `<polygon points="${avgPts.map(p => p.join(',')).join(' ')}" fill="none" stroke="#6b7280" stroke-width="3" stroke-dasharray="8 7"/>` : '') +
        `<polygon points="${pts.map(p => p.join(',')).join(' ')}" fill="url(#v28RadarFill)" stroke="url(#v28RadarStroke)" stroke-width="6"/>` +
        pts.map((p,i) => `<circle cx="${p[0]}" cy="${p[1]}" r="9" fill="#fff" stroke="${v28ScoreColor(vals[i])}" stroke-width="5"/>`).join('') +
        (avgCfg ? avgPts.map((p,i) => `<circle cx="${p[0]}" cy="${p[1]}" r="5" fill="#fff" stroke="#6b7280" stroke-width="3"/>`).join('') : '') +
        keys.map((k,i) => {
          const p = point(i, rr + 92);
          const side = p[0] < cx - 18 ? 'right' : (p[0] > cx + 18 ? 'left' : 'center');
          const color = v28ScoreColor(vals[i]);
          const w = k === 'strategy' ? 520 : 380;
          const h = 126;
          const x = side === 'right' ? p[0] - w : (side === 'center' ? p[0] - w/2 : p[0]);
          const y = k === 'strategy' ? p[1] - 34 : p[1] - 58;
          const avgLabel = avgCfg ? ` <small>/ ср. ${Math.round(avgVals[i])}</small>` : '';
          return `<foreignObject class="v28-radar-label-fo" x="${x}" y="${y}" width="${w}" height="${h}">
            <div xmlns="http://www.w3.org/1999/xhtml" class="v28-radar-label ${side}" style="--radar-score-color:${color}">
              <div class="v28-radar-title"><i class="fa-solid ${icons[k]}"></i><span>${names[k]}</span></div>
              <div class="v28-radar-score">${vals[i]}${avgLabel}</div>
            </div>
          </foreignObject>`;
        }).join('');
    }

    function v28DomainMaturityLevel(score0to5){
      const x = Number(score0to5) || 0;
      if(x < 0.5) return 0;
      if(x < 1.5) return 1;
      if(x < 2.5) return 2;
      if(x < 3.5) return 3;
      if(x < 4.5) return 4;
      return 5;
    }
