    function pdfGetText(id, fallback){
      const el=document.getElementById(id);
      return (el && (el.innerText || el.textContent || '').trim()) || fallback || '—';
    }

    function pdfDownloadBlob(blob, filename){
      const url=URL.createObjectURL(blob);
      const a=document.createElement('a');
      a.href=url;
      a.download=filename;
      a.style.display='none';
      document.body.appendChild(a);
      a.click();
      setTimeout(()=>{URL.revokeObjectURL(url);a.remove();}, 1000);
    }

    function pdfWrapText(ctx, text, x, y, maxWidth, lineHeight, maxLines){
      const words=String(text||'').replace(/\s+/g,' ').trim().split(' ');
      let line='', lines=[];
      for(const word of words){
        const test=line ? line + ' ' + word : word;
        if(ctx.measureText(test).width > maxWidth && line){
          lines.push(line);
          line=word;
          if(maxLines && lines.length >= maxLines) break;
        }else{
          line=test;
        }
      }
      if(line && (!maxLines || lines.length < maxLines)) lines.push(line);
      if(maxLines && lines.length > maxLines) lines=lines.slice(0,maxLines);
      lines.forEach((ln,i)=>ctx.fillText(ln, x, y+i*lineHeight));
      return y + lines.length*lineHeight;
    }

    function pdfRoundRect(ctx, x, y, w, h, r, fill, stroke){
      ctx.beginPath();
      ctx.moveTo(x+r,y);
      ctx.lineTo(x+w-r,y);
      ctx.quadraticCurveTo(x+w,y,x+w,y+r);
      ctx.lineTo(x+w,y+h-r);
      ctx.quadraticCurveTo(x+w,y+h,x+w-r,y+h);
      ctx.lineTo(x+r,y+h);
      ctx.quadraticCurveTo(x,y+h,x,y+h-r);
      ctx.lineTo(x,y+r);
      ctx.quadraticCurveTo(x,y,x+r,y);
      ctx.closePath();
      if(fill) ctx.fill();
      if(stroke) ctx.stroke();
    }

    function pdfDrawCard(ctx, x, y, w, h){
      ctx.save();
      ctx.fillStyle='#ffffff';
      ctx.strokeStyle='#e3e8f0';
      ctx.lineWidth=2;
      ctx.shadowColor='rgba(16,24,40,.08)';
      ctx.shadowBlur=18;
      ctx.shadowOffsetY=8;
      pdfRoundRect(ctx,x,y,w,h,18,true,true);
      ctx.restore();
    }

    function pdfDrawGauge(ctx, x, y, w, score){
      const cx=x+w/2, cy=y+170, r=130;
      ctx.save();
      ctx.lineWidth=38;
      ctx.lineCap='butt';
      ctx.strokeStyle='#ecf0f5';
      ctx.beginPath();ctx.arc(cx,cy,r,Math.PI,0);ctx.stroke();
      const grad=ctx.createLinearGradient(cx-r,y,cx+r,y);
      grad.addColorStop(0,'#18c85f');grad.addColorStop(.55,'#08b39f');grad.addColorStop(1,'#32a7e3');
      ctx.strokeStyle=grad;
      ctx.beginPath();ctx.arc(cx,cy,r,Math.PI,Math.PI+(Math.max(0,Math.min(100,score))/100)*Math.PI);ctx.stroke();
      ctx.fillStyle='#0b1535';ctx.textAlign='center';ctx.font='900 74px Arial';ctx.fillText(String(score),cx,cy-8);
      ctx.font='700 24px Arial';ctx.fillStyle='#344054';ctx.fillText('из 100',cx,cy+42);
      ctx.textAlign='left';ctx.font='20px Arial';ctx.fillStyle='#344054';ctx.fillText('0',x+18,cy+36);ctx.fillText('100',x+w-58,cy+36);
      ctx.restore();
    }

    function pdfDrawRadar(ctx, x, y, w, h, domains, bench){
      const labels=['Стратегия','Данные','Процессы','Компетенции','Технологии'];
      const cx=x+w/2, cy=y+h/2+10, R=Math.min(w,h)*0.33;
      function pt(i,val){const ang=-Math.PI/2+i*2*Math.PI/5; const rr=R*(val/100); return [cx+Math.cos(ang)*rr, cy+Math.sin(ang)*rr];}
      ctx.save();
      ctx.strokeStyle='#dfe5ee'; ctx.lineWidth=1.5;
      for(const t of [25,50,75,100]){
        ctx.beginPath();
        for(let i=0;i<5;i++){const [px,py]=pt(i,t); i?ctx.lineTo(px,py):ctx.moveTo(px,py)}
        ctx.closePath(); ctx.stroke();
      }
      for(let i=0;i<5;i++){const [px,py]=pt(i,100);ctx.beginPath();ctx.moveTo(cx,cy);ctx.lineTo(px,py);ctx.stroke();}
      ctx.font='700 19px Arial';ctx.fillStyle='#0b1535';ctx.textAlign='center';
      for(let i=0;i<5;i++){const [px,py]=pt(i,118); const label=labels[i];
        if(i===0){ctx.fillText('Стратегия',px,py-8);ctx.fillText('и целеполагание',px,py+16)}
        else ctx.fillText(label,px,py+6);
      }
      function poly(vals, stroke, fill, dash){
        ctx.beginPath();
        vals.forEach((v,i)=>{const [px,py]=pt(i,v); i?ctx.lineTo(px,py):ctx.moveTo(px,py)});
        ctx.closePath(); ctx.fillStyle=fill; ctx.fill(); ctx.strokeStyle=stroke; ctx.lineWidth=4; ctx.setLineDash(dash||[]); ctx.stroke(); ctx.setLineDash([]);
        vals.forEach((v,i)=>{const [px,py]=pt(i,v); ctx.beginPath();ctx.arc(px,py,5,0,Math.PI*2);ctx.fillStyle=stroke;ctx.fill();});
      }
      poly(bench,'#65758f','rgba(101,117,143,.06)',[10,8]);
      poly(domains,'#00a651','rgba(0,166,81,.12)',[]);
      ctx.restore();
    }

    function pdfCanvasPage(){
      const canvas=document.createElement('canvas');
      canvas.width=1754; canvas.height=1240; // A4 landscape at ~150 dpi
      const ctx=canvas.getContext('2d');
      ctx.fillStyle='#ffffff';ctx.fillRect(0,0,canvas.width,canvas.height);
      return {canvas,ctx};
    }

