    function pdfMakeFromJpegs(jpegs, pageW, pageH){
      const enc=new TextEncoder();
      const chunks=[]; let offset=0; const offsets=[0];
      function add(chunk){ if(typeof chunk==='string') chunk=enc.encode(chunk); chunks.push(chunk); offset+=chunk.length; }
      // Важно: без PDF-заголовка браузер скачивает битый файл и показывает «Не удалось загрузить документ PDF».
      add('%PDF-1.4\n%\xE2\xE3\xCF\xD3\n');
      function obj(n, body){ offsets[n]=offset; add(`${n} 0 obj\n`); add(body); add(`\nendobj\n`); }
      const pageCount=jpegs.length;
      obj(1,'<< /Type /Catalog /Pages 2 0 R >>');
      const kids=[]; for(let i=0;i<pageCount;i++) kids.push(`${3+i*3} 0 R`);
      obj(2,`<< /Type /Pages /Kids [${kids.join(' ')}] /Count ${pageCount} >>`);
      jpegs.forEach((img,i)=>{
        const pageObj=3+i*3, contentObj=pageObj+1, imageObj=pageObj+2, imName=`Im${i+1}`;
        obj(pageObj,`<< /Type /Page /Parent 2 0 R /MediaBox [0 0 ${pageW} ${pageH}] /Resources << /XObject << /${imName} ${imageObj} 0 R >> >> /Contents ${contentObj} 0 R >>`);
        const stream=`q\n${pageW} 0 0 ${pageH} 0 0 cm\n/${imName} Do\nQ`;
        obj(contentObj,`<< /Length ${stream.length} >>\nstream\n${stream}\nendstream`);
        offsets[imageObj]=offset; add(`${imageObj} 0 obj\n<< /Type /XObject /Subtype /Image /Width ${img.width} /Height ${img.height} /ColorSpace /DeviceRGB /BitsPerComponent 8 /Filter /DCTDecode /Length ${img.bytes.length} >>\nstream\n`); add(img.bytes); add(`\nendstream\nendobj\n`);
      });
      const xref=offset;
      add(`xref\n0 ${pageCount*3+3}\n0000000000 65535 f \n`);
      for(let i=1;i<=pageCount*3+2;i++) add(`${String(offsets[i]).padStart(10,'0')} 00000 n \n`);
      add(`trailer\n<< /Size ${pageCount*3+3} /Root 1 0 R >>\nstartxref\n${xref}\n%%EOF`);
      return new Blob(chunks,{type:'application/pdf'});
    }

    function pdfCanvasToJpegBytes(canvas, quality){
      const b64=canvas.toDataURL('image/jpeg', quality || 0.94).split(',')[1];
      const bin=atob(b64);
      const bytes=new Uint8Array(bin.length);
      for(let i=0;i<bin.length;i++) bytes[i]=bin.charCodeAt(i);
      return {bytes,width:canvas.width,height:canvas.height};
    }



    function pdfDrawWrappedCanvasText(ctx, text, x, y, maxWidth, lineHeight, maxLines){
      const words=String(text || '').replace(/\s+/g,' ').trim().split(' ').filter(Boolean);
      let line='';
      let lines=[];
      for(const word of words){
        const test=line ? line+' '+word : word;
        if(ctx.measureText(test).width > maxWidth && line){
          lines.push(line);
          line=word;
          if(maxLines && lines.length >= maxLines) break;
        }else{
          line=test;
        }
      }
      if(line && (!maxLines || lines.length < maxLines)) lines.push(line);
      if(maxLines && lines.length > maxLines) lines=lines.slice(0,maxLines);
      lines.forEach((ln,i)=>ctx.fillText(ln,x,y+i*lineHeight));
      return y+lines.length*lineHeight;
    }

    function pdfMountGaugeCanvasFallback(){
      const card=document.querySelector('.results-screen .result-gauge-card') || document.querySelector('.result-gauge-card');
      if(!card) return function(){};
      const rect=card.getBoundingClientRect();
      const w=Math.max(320, Math.ceil(rect.width || card.offsetWidth || 420));
      const h=Math.max(420, Math.ceil(rect.height || card.offsetHeight || 520));
      const ratio=2;
      const canvas=document.createElement('canvas');
      canvas.width=w*ratio;
      canvas.height=h*ratio;
      canvas.style.position='absolute';
      canvas.style.inset='0';
      canvas.style.width='100%';
      canvas.style.height='100%';
      canvas.style.zIndex='1000';
      canvas.style.pointerEvents='none';
      canvas.style.borderRadius='12px';
      canvas.setAttribute('data-pdf-gauge-fallback','1');

      const ctx=canvas.getContext('2d');
      ctx.scale(ratio,ratio);
      ctx.clearRect(0,0,w,h);
      ctx.fillStyle='#ffffff';
      ctx.fillRect(0,0,w,h);

      const score=parseInt((document.getElementById('v28ScoreValue')||{}).textContent || '0',10) || 0;
      const level=((document.getElementById('v28ScoreLevel')||{}).textContent || 'Уровень зрелости').trim();
      const note=((document.getElementById('v28ScoreNote')||{}).textContent || '').trim();
      const scoreColor=(typeof v28ScoreColor==='function') ? v28ScoreColor(score) : '#ffd23f';

      ctx.fillStyle='#0b1535';
      ctx.font='900 18px Arial, sans-serif';
      pdfDrawWrappedCanvasText(ctx,'1. Шкала зрелости управления',22,34,w-44,22,2);

      const cx=w/2;
      const cy=Math.min(235, h*0.46);
      const r=Math.min(w*0.34, 145);
      ctx.lineWidth=24;
      ctx.lineCap='round';
      ctx.strokeStyle='#e8ecf3';
      ctx.beginPath();
      ctx.arc(cx,cy,r,Math.PI,0,false);
      ctx.stroke();

      const grad=ctx.createLinearGradient(cx-r,0,cx+r,0);
      grad.addColorStop(0,'#d71920');
      grad.addColorStop(.36,'#f36f21');
      grad.addColorStop(.56,'#ffd23f');
      grad.addColorStop(1,'#1eb43f');
      ctx.strokeStyle=grad;
      ctx.beginPath();
      ctx.arc(cx,cy,r,Math.PI,Math.PI+(score/100)*Math.PI,false);
      ctx.stroke();

      const angle=Math.PI-(score/100)*Math.PI;
      const kx=cx+Math.cos(angle)*r;
      const ky=cy-Math.sin(angle)*r;
      ctx.fillStyle='#fff';
      ctx.strokeStyle=scoreColor;
      ctx.lineWidth=6;
      ctx.beginPath();
      ctx.arc(kx,ky,12,0,Math.PI*2);
      ctx.fill();
      ctx.stroke();

      ctx.textAlign='center';
      ctx.fillStyle=scoreColor;
      ctx.font='900 56px Arial, sans-serif';
      ctx.fillText(String(score),cx,cy-12);
      ctx.fillStyle='#0b1535';
      ctx.font='800 20px Arial, sans-serif';
      ctx.fillText('из 100',cx,cy+20);
      ctx.fillStyle=scoreColor;
      ctx.font='900 20px Arial, sans-serif';
      ctx.fillText(level,cx,cy+56);

      ctx.textAlign='center';
      ctx.fillStyle='#66728a';
      ctx.font='17px Arial, sans-serif';
      const lines=[];
      const words=note.replace(/\s+/g,' ').split(' ').filter(Boolean);
      let line='';
      const maxW=w-60;
      for(const word of words){
        const test=line?line+' '+word:word;
        if(ctx.measureText(test).width>maxW && line){lines.push(line);line=word;} else line=test;
      }
      if(line) lines.push(line);
      lines.slice(0,4).forEach((ln,i)=>ctx.fillText(ln,cx,cy+105+i*23));

      const oldPosition=card.style.position;
      if(getComputedStyle(card).position==='static') card.style.position='relative';
      card.appendChild(canvas);
      return function(){
        canvas.remove();
        card.style.position=oldPosition;
      };
    }

    async function pdfCaptureVisibleResults(){
      const report=document.querySelector('.results-screen .results-mockup') || document.querySelector('.results-mockup');
      if(!report) throw new Error('Results block not found');

      await loadScriptOnce('https://cdnjs.cloudflare.com/ajax/libs/html2canvas/1.4.1/html2canvas.min.js');
      if(document.fonts && document.fonts.ready) await document.fonts.ready;

      document.documentElement.classList.add('pdf-direct-export-mode');
      document.body.classList.add('pdf-direct-export-mode');
      report.classList.add('pdf-export-target');
      const cleanupGaugeFallback=pdfMountGaugeCanvasFallback();

      const previousScrollX=window.scrollX || window.pageXOffset || 0;
      const previousScrollY=window.scrollY || window.pageYOffset || 0;
      window.scrollTo(0,0);
      await new Promise(resolve=>requestAnimationFrame(()=>requestAnimationFrame(resolve)));

      try{
        const rect=report.getBoundingClientRect();
        const canvas=await window.html2canvas(report,{
          backgroundColor:'#ffffff',
          scale:Math.min(2, window.devicePixelRatio || 1.5),
          useCORS:true,
          allowTaint:false,
          logging:false,
          width:Math.ceil(rect.width),
          height:Math.ceil(report.scrollHeight),
          windowWidth:Math.max(document.documentElement.scrollWidth, Math.ceil(rect.width)),
          windowHeight:Math.max(document.documentElement.scrollHeight, Math.ceil(report.scrollHeight)),
          scrollX:0,
          scrollY:0
        });
        return canvas;
      }finally{
        if(typeof cleanupGaugeFallback === 'function') cleanupGaugeFallback();
        report.classList.remove('pdf-export-target');
        document.body.classList.remove('pdf-direct-export-mode');
        document.documentElement.classList.remove('pdf-direct-export-mode');
        window.scrollTo(previousScrollX,previousScrollY);
      }
    }

    function pdfSplitCanvasToLandscapePages(sourceCanvas){
      const pageRatio=595/842; // A4 landscape: height / width
      const sliceHeight=Math.floor(sourceCanvas.width * pageRatio);
      const pages=[];
      for(let y=0;y<sourceCanvas.height;y+=sliceHeight){
        const pageCanvas=document.createElement('canvas');
        pageCanvas.width=sourceCanvas.width;
        pageCanvas.height=sliceHeight;
        const ctx=pageCanvas.getContext('2d');
        ctx.fillStyle='#ffffff';
        ctx.fillRect(0,0,pageCanvas.width,pageCanvas.height);
        ctx.drawImage(
          sourceCanvas,
          0,y,sourceCanvas.width,Math.min(sliceHeight,sourceCanvas.height-y),
          0,0,pageCanvas.width,Math.min(sliceHeight,sourceCanvas.height-y)
        );
        pages.push(pageCanvas);
      }
      return pages;
    }

    async function downloadPdfReport(){
      updateAll();
      const btn=document.getElementById('exportBtn');
      const oldText=btn ? btn.innerHTML : '';
      if(btn){btn.disabled=true;btn.innerHTML='<i class="fa-regular fa-file-pdf"></i> Формируем PDF...';}
      try{
        const screenshotCanvas=await pdfCaptureVisibleResults();
        const pageCanvases=pdfSplitCanvasToLandscapePages(screenshotCanvas);
        const jpegs=pageCanvases.map(canvas=>pdfCanvasToJpegBytes(canvas,0.94));
        const blob=pdfMakeFromJpegs(jpegs,842,595);
        const company=(document.querySelector('[name="company"]')||{}).value || 'company';
        pdfDownloadBlob(blob,`sber2b-digital-maturity-report-${safeFilePart(company)}.pdf`);
      }catch(err){
        console.error('PDF export failed:',err);
        alert('Не удалось сформировать PDF в браузере. Попробуйте обновить страницу и нажать кнопку еще раз.');
      }finally{
        if(btn){btn.disabled=false;btn.innerHTML=oldText;}
      }
    }

    function downloadJson(){
      const p=updateAll(),blob=new Blob([JSON.stringify(p,null,2)],{type:'application/json'}),a=document.createElement('a');
      a.href=URL.createObjectURL(blob);a.download='sber2b-digital-ai-maturity-result.json';a.click();URL.revokeObjectURL(a.href);
    }

    function xlsxSafe(value){
      if(value===undefined || value===null)return '';
      if(Array.isArray(value))return value.join(', ');
      if(typeof value==='object')return JSON.stringify(value, null, 2);
      return value;
    }

    function aoaToHtmlTable(aoa){
      return '<table>' + aoa.map(row => '<tr>' + row.map(cell => `<td>${String(xlsxSafe(cell)).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;')}</td>`).join('') + '</tr>').join('') + '</table>';
    }

