    function downloadExcel(){
      const p = updateAll();
      const industryText = document.getElementById('industry')?.selectedOptions?.[0]?.text || p.context.industry || '';
      const departments = p.context.department || [];
      const domainNames = {strategy:'Стратегия',data:'Данные',tech:'Технологии',competence:'Компетенции',process:'Процессы'};
      const raw = p.raw_answers || {};

      const anketa = [
        ['Раздел','Поле','Значение'],
        ['Контакт','ФИО',p.contact.full_name],
        ['Контакт','Компания',p.contact.company],
        ['Контакт','ИНН',p.contact.company_inn],
        ['Контакт','Email',p.contact.company_email],
        ['Контакт','Телефон',p.contact.phone],
        ['Контекст','Отрасль',industryText],
        ['Контекст','Подразделение',departments.join(', ')],
        ['Контекст','Согласие на обработку ПД',p.contact.pd_consent ? 'Да' : 'Нет']
      ];

      const answers = [['№','ID вопроса','Домен','Вопрос','Ответ 0–5','Ответ 0–100']];
      syncCoreQuestions();
      coreQuestions.forEach((q,i)=>{
        const v = Number(raw[q.id] || 0);
        answers.push([i+1,q.id,domainNames[q.domain] || q.domain,q.title,v,Math.round(v/5*100)]);
      });

      const results = [
        ['Показатель','Значение'],
        ['Индекс цифровой зрелости 0–5',p.scoring.overall_index_0_5],
        ['Индекс цифровой зрелости 0–100',p.scoring.overall_index_0_100],
        ['Уровень зрелости',p.scoring.maturity_level],
        ['Рекомендуемый тип консалтинга',p.recommendation.primary_project_type],
        ['Приоритет / пояснение',p.recommendation.priority],
        ['Правило дерева решений',p.recommendation.tree_rule_path],
        ['Уверенность модели',p.recommendation.confidence]
      ];

      const domainsSheet = [['Домен','Балл 0–5','Балл 0–100','Статус']];
      Object.entries(p.scoring.domain_scores_0_5 || {}).forEach(([key,value])=>{
        const score100 = Math.round(Number(value)/5*100);
        domainsSheet.push([domainNames[key] || key,value,score100,dmqStatus(score100).label]);
      });

      const hypotheses = [['Тип','Название','Описание']];
      (p.recommendation.hypotheses || []).forEach(x=>hypotheses.push(['Гипотеза',x.title,x.description]));
      (p.recommendation.recommended_actions || []).forEach(x=>hypotheses.push(['Рекомендация',x.title,x.description]));

      const tech = [['Раздел','Поле','Значение']];
      Object.entries(raw).forEach(([key,value])=>tech.push(['Raw answers',key,xlsxSafe(value)]));
      tech.push(['Meta','Дата формирования',p.meta.created_at]);
      tech.push(['Meta','Модель',p.meta.recommendation_model]);
      tech.push(['Meta','Версия модели',p.meta.model_version]);

      const sheets = [
        {name:'Анкета', aoa:anketa},
        {name:'Ответы', aoa:answers},
        {name:'Результаты', aoa:results},
        {name:'Домены', aoa:domainsSheet},
        {name:'Гипотезы', aoa:hypotheses},
        {name:'Технические данные', aoa:tech}
      ];
      const filename = `sber2b-digital-maturity-result-${new Date().toISOString().slice(0,10)}.xlsx`;

      if(!window.XLSX){
        downloadExcelFallback(sheets, filename);
        return;
      }

      const wb = XLSX.utils.book_new();
      sheets.forEach(sheet=>{
        const ws = XLSX.utils.aoa_to_sheet(sheet.aoa);
        ws['!cols'] = sheet.aoa[0].map((_,i)=>({wch:Math.min(70, Math.max(14, ...sheet.aoa.map(row=>String(xlsxSafe(row[i] || '')).length + 2)))}));
        XLSX.utils.book_append_sheet(wb, ws, sheet.name.slice(0,31));
      });
      XLSX.writeFile(wb, filename);
    }

