(function(){
  const revenueMaturityMap = {
    '0-0.5': {label:'до 0,5 млрд ₽', maturityLevel:0, columnIndex:1, columnLabel:'0. Отсутствующий'},
    '0.5-1': {label:'0,5–1 млрд ₽', maturityLevel:1, columnIndex:2, columnLabel:'1. Начальный'},
    '1-5': {label:'1–5 млрд ₽', maturityLevel:2, columnIndex:3, columnLabel:'2. Управляемый'},
    '5-10': {label:'5–10 млрд ₽', maturityLevel:2, columnIndex:3, columnLabel:'2. Управляемый'},
    '10-25': {label:'10–25 млрд ₽', maturityLevel:3, columnIndex:4, columnLabel:'3. Определяемый'},
    '25-50': {label:'25–50 млрд ₽', maturityLevel:4, columnIndex:5, columnLabel:'4. Измеряемый'},
    '50+': {label:'50+ млрд ₽', maturityLevel:5, columnIndex:6, columnLabel:'5. Оптимизируемый'}
  };
  const maturityRows = [
    {key:'strategy', label:'Стратегия', userId:'tblStrategy'},
    {key:'data', label:'Данные', userId:'tblData'},
    {key:'process', label:'Процессы', userId:'tblProcess'},
    {key:'competence', label:'Компетенции', userId:'tblCompetence'},
    {key:'tech', label:'Технологии', userId:'tblTech'},
    {key:'index', label:'Индекс зрелости', userId:'tblIndex'}
  ];

  function getFieldValue(name){
    if(typeof val === 'function') return val(name);
    const el = document.querySelector(`[name="${name}"]`);
    return el ? el.value : '';
  }

  function getRevenueInfo(){
    const select = document.querySelector('[name="revenue"]');
    const value = select ? select.value : '';
    const base = revenueMaturityMap[value] || {label:'не указана', maturityLevel:null, columnIndex:null, columnLabel:'—'};
    const visibleLabel = select && select.selectedOptions && select.selectedOptions[0] ? select.selectedOptions[0].textContent.trim() : base.label;
    return {...base, value, label: value ? visibleLabel : 'не указана'};
  }

  function toNumber(x){
    const n = Number(String(x || '').replace(',', '.').replace(/[^0-9.\-]/g, ''));
    return Number.isFinite(n) ? n : null;
  }

  function diffColor(diff){
    if(diff === null || !Number.isFinite(diff)) return '#344054';
    const cap = Math.min(1, Math.abs(diff) / 45);
    if(diff > 0){
      const g = Math.round(85 - 35 * cap);
      return `rgb(215, ${g}, ${g})`;
    }
    if(diff < 0){
      const r = Math.round(20 - 5 * cap);
      const b = Math.round(85 - 45 * cap);
      return `rgb(${r}, 140, ${b})`;
    }
    return '#344054';
  }

  function getCellNumber(cell){
    if(!cell) return null;
    if(cell.dataset && cell.dataset.userScore !== undefined){
      const n = Number(cell.dataset.userScore);
      return Number.isFinite(n) ? n : null;
    }
    return toNumber(cell.textContent);
  }

  function getGaugeMaturityColor(){
    const rootStyle = getComputedStyle(document.documentElement);
    const v28Color = rootStyle.getPropertyValue('--v28-score-color').trim();
    if(v28Color) return v28Color;
    const cssColor = rootStyle.getPropertyValue('--maturity-color').trim();
    if(cssColor) return cssColor;
    const idx = document.getElementById('tblIndex');
    const score = getCellNumber(idx) || 0;
    if(typeof v28ScoreColor === 'function') return v28ScoreColor(score);
    if(typeof maturityColor === 'function') return maturityColor(score);
    if(score < 25) return '#8b0000';
    if(score < 65) return '#ff8a00';
    return '#1eb43f';
  }

  function rgbaFromColor(color, alpha){
    if(!color) return `rgba(16,127,140,${alpha})`;
    if(color.startsWith('#')){
      const hex = color.replace('#','');
      const full = hex.length === 3 ? hex.split('').map(x=>x+x).join('') : hex;
      const n = parseInt(full,16);
      if(Number.isFinite(n)) return `rgba(${(n>>16)&255},${(n>>8)&255},${n&255},${alpha})`;
    }
    const m = color.match(/rgba?\(([^)]+)\)/i);
    if(m){
      const parts = m[1].split(',').map(x=>x.trim()).slice(0,3);
      return `rgba(${parts.join(',')},${alpha})`;
    }
    return `rgba(16,127,140,${alpha})`;
  }

  function getMaturityTableComparison(){
    const revenue = getRevenueInfo();
    const result = {revenue_range: revenue.value, revenue_range_label: revenue.label, selected_maturity_level: revenue.maturityLevel, selected_maturity_label: revenue.columnLabel, benchmark_by_revenue: {}, gap_benchmark_minus_user: {}, percent_vs_benchmark: {}};
    if(!revenue.columnIndex) return result;
    maturityRows.forEach(row => {
      const userEl = document.getElementById(row.userId);
      const userScore = getCellNumber(userEl);
      const tr = userEl ? userEl.closest('tr') : null;
      const benchmarkScore = tr && tr.cells[revenue.columnIndex] ? toNumber(tr.cells[revenue.columnIndex].textContent) : null;
      const gap = (benchmarkScore !== null && userScore !== null) ? Math.round(benchmarkScore - userScore) : null;
      result.benchmark_by_revenue[row.key] = benchmarkScore;
      result.gap_benchmark_minus_user[row.key] = gap;
      result.percent_vs_benchmark[row.key] = (benchmarkScore && userScore !== null && userScore > 0) ? Math.round(((benchmarkScore - userScore) / Math.max(Math.abs(benchmarkScore), 1)) * 100) : null;
    });
    return result;
  }

  function renderUserCell(userEl, userScore, benchmarkScore){
    if(!userEl || userScore === null) return;
    userEl.dataset.userScore = userScore;
    const diff = (benchmarkScore !== null && Number.isFinite(benchmarkScore)) ? userScore - benchmarkScore : null;
    const pct = (diff === null || !benchmarkScore || userScore <= 0 || diff === 0) ? null : Math.round((Math.abs(diff) / Math.max(Math.abs(benchmarkScore), 1)) * 100);
    let badge = '';
    if(pct !== null && Number.isFinite(pct)){
      const cls = diff > 0 ? 'is-up' : 'is-down';
      const arrow = '↑';
      const title = diff > 0 ? `Выше квинтиля на ${Math.round(Math.abs(diff))} баллов` : `Ниже квинтиля на ${Math.round(Math.abs(diff))} баллов`;
      badge = `<span class="maturity-gap-badge ${cls}" title="${title}"><i class="fa-solid fa-angles-up"></i> ${Math.abs(pct)}%</span>`;
    }
    userEl.innerHTML = `<span class="maturity-user-cell"><span class="maturity-user-score">${userScore}</span>${badge}</span>`;
  }

  function updateMaturityRevenueComparison(){
    const revenue = getRevenueInfo();
    const table = document.querySelector('.maturity-table');
    if(!table) return;
    const color = getGaugeMaturityColor();
    const softBg = rgbaFromColor(color, .10);
    const softerBg = rgbaFromColor(color, .06);
    table.style.setProperty('--maturity-color', color);

    const yourHeaderSmall = table.querySelector('th.your-col small');
    if(yourHeaderSmall) yourHeaderSmall.textContent = `(${revenue.label})`;
    const revenueRow = table.querySelector('tr.revenue-row');
    if(revenueRow && revenueRow.cells[7]) revenueRow.cells[7].textContent = revenue.label;

    Array.from(table.querySelectorAll('td, th')).forEach(cell => {
      cell.classList.remove('maturity-selected-col','maturity-your-selected','maturity-col-start','maturity-col-end');
      cell.style.outline = '';
      cell.style.outlineOffset = '';
      cell.style.boxShadow = '';
      if(!cell.classList.contains('your-col')) cell.style.background = '';
      cell.style.borderColor = '';
    });

    table.querySelectorAll('th.your-col, td:last-child').forEach(cell => {
      cell.classList.add('maturity-your-selected');
      cell.style.background = softBg;
      cell.style.borderLeftColor = color;
      cell.style.borderRightColor = color;
    });

    if(revenue.columnIndex && revenueRow && revenueRow.cells[revenue.columnIndex]){
      revenueRow.cells[revenue.columnIndex].textContent = `${revenue.label} · выбранный диапазон`;
    }

    if(revenue.columnIndex){
      table.querySelectorAll('tr').forEach(tr => {
        const isLevelHeaderRow = tr.parentElement && tr.parentElement.tagName === 'THEAD' && tr.cells.length === 6;
        const targetIndex = isLevelHeaderRow ? revenue.columnIndex - 1 : revenue.columnIndex;
        const c = tr.cells && tr.cells[targetIndex];
        if(c){
          c.classList.add('maturity-selected-col');
          c.style.background = softerBg;
          c.style.outline = `2px solid ${color}`;
          c.style.outlineOffset = '-2px';
          c.style.boxShadow = `inset 0 0 0 999px ${rgbaFromColor(color,.05)}`;
        }
      });
    }

    maturityRows.forEach(row => {
      const userEl = document.getElementById(row.userId);
      if(!userEl) return;
      const rawUserScore = getCellNumber(userEl);
      const tr = userEl.closest('tr');
      if(!tr) return;
      const selectedBenchmark = revenue.columnIndex && tr.cells[revenue.columnIndex] ? toNumber(tr.cells[revenue.columnIndex].textContent) : null;
      renderUserCell(userEl, rawUserScore, selectedBenchmark);
      for(let i=1;i<=6;i++){
        const cell = tr.cells[i];
        if(!cell) continue;
        const benchmarkScore = toNumber(cell.textContent);
        const diff = benchmarkScore !== null && rawUserScore !== null ? benchmarkScore - rawUserScore : null;
        cell.style.color = diffColor(diff);
        cell.style.fontWeight = '900';
        cell.title = diff === null ? '' : `Бенчмарк − ваша компания: ${Math.round(diff)} баллов`;
      }
    });
  }

  const originalPayload = window.payload || (typeof payload === 'function' ? payload : null);
  if(originalPayload){
    window.payload = payload = function(s,o,r,h,rs){
      const p = originalPayload(s,o,r,h,rs);
      p.contact = p.contact || {};
      p.context = p.context || {};
      p.scoring = p.scoring || {};
      const revenue = getRevenueInfo();
      p.contact.role = getFieldValue('role');
      p.context.revenue_range = revenue.value;
      p.context.revenue_range_label = revenue.label;
      p.context.revenue_maturity_level = revenue.maturityLevel;
      p.context.revenue_maturity_label = revenue.columnLabel;
      p.scoring.maturity_table_comparison = getMaturityTableComparison();
      return p;
    };
  }

  const originalRenderAll = window.v28RenderAll || (typeof v28RenderAll === 'function' ? v28RenderAll : null);
  if(originalRenderAll){
    window.v28RenderAll = v28RenderAll = function(s, score, recoObj){
      originalRenderAll(s, score, recoObj);
      updateMaturityRevenueComparison();
    };
  }

  const revenueSelect = document.querySelector('[name="revenue"]');
  if(revenueSelect){
    revenueSelect.addEventListener('change', function(){
      updateMaturityRevenueComparison();
      if(typeof updateAll === 'function') updateAll();
    });
  }

  if(typeof updateAll === 'function') updateAll();
})();


