/* v30: dynamic maturity table bound to questionnaire answers, selected revenue quintile and v28 gauge color */
(function(){
  const DMQ_TABLE_ROWS = [
    {key:'strategy', id:'tblStrategy'},
    {key:'data', id:'tblData'},
    {key:'process', id:'tblProcess'},
    {key:'competence', id:'tblCompetence'},
    {key:'tech', id:'tblTech'},
    {key:'index', id:'tblIndex'}
  ];
  const DMQ_REVENUE_TO_COL = {
    '0-0.5': {col:1, label:'до 0,5 млрд ₽'},
    '0.5-1': {col:2, label:'0,5–1 млрд ₽'},
    '1-5': {col:3, label:'1–5 млрд ₽'},
    '5-10': {col:3, label:'5–10 млрд ₽'},
    '10-25': {col:4, label:'10–25 млрд ₽'},
    '25-50': {col:5, label:'25–50 млрд ₽'},
    '50+': {col:6, label:'50+ млрд ₽'}
  };
  function n(x){
    const v = Number(String(x == null ? '' : x).replace(',', '.').replace(/[^0-9.-]/g,''));
    return Number.isFinite(v) ? v : null;
  }
  function score100(v){ return Math.round((Number(v)||0)/5*100); }
  function colorForScore(score){
    if(typeof v28ScoreColor === 'function') return v28ScoreColor(score);
    if(typeof maturityColor === 'function') return maturityColor(score);
    if(score < 25) return '#8b0000';
    if(score < 65) return '#ff8a00';
    return '#1eb43f';
  }
  function rgba(hex, a){
    const h = String(hex || '').trim();
    if(h[0] !== '#') return `rgba(16,127,140,${a})`;
    const full = h.length === 4 ? '#'+h.slice(1).split('').map(c=>c+c).join('') : h;
    const v = parseInt(full.slice(1), 16);
    if(!Number.isFinite(v)) return `rgba(16,127,140,${a})`;
    return `rgba(${(v>>16)&255},${(v>>8)&255},${v&255},${a})`;
  }
  function diffColor(diff){
    if(diff == null || !Number.isFinite(diff)) return '#344054';
    const cap = Math.min(1, Math.abs(diff)/45);
    if(diff > 0) return `rgb(${Math.round(190+35*cap)}, ${Math.round(90-35*cap)}, ${Math.round(90-35*cap)})`;
    if(diff < 0) return `rgb(${Math.round(20-5*cap)}, ${Math.round(145-25*cap)}, ${Math.round(75-35*cap)})`;
    return '#344054';
  }
  function currentRevenue(){
    const sel = document.querySelector('[name="revenue"]');
    const value = sel ? sel.value : '';
    const mapped = DMQ_REVENUE_TO_COL[value] || {col:null, label:'не указана'};
    const label = value && sel && sel.selectedOptions && sel.selectedOptions[0] ? sel.selectedOptions[0].textContent.trim() : mapped.label;
    return {...mapped, value, label};
  }
  function setUserCell(id, value, benchmark){
    const el = document.getElementById(id);
    if(!el) return;
    el.dataset.userScore = String(value);
    const diff = (benchmark == null || !Number.isFinite(benchmark)) ? null : value - benchmark;
    const pct = (diff == null || benchmark == null || !Number.isFinite(benchmark) || benchmark === 0 || value <= 0 || diff === 0) ? null : Math.round(Math.abs(diff) / Math.max(Math.abs(benchmark), 1) * 100);
    const color = colorForScore(value);
    let badge = '';
    if(pct != null && Number.isFinite(pct)){
      const cls = diff > 0 ? 'is-up' : 'is-down';
      const arrow = '↑';
      const title = diff > 0 ? `Выше квинтиля на ${Math.round(Math.abs(diff))} баллов` : `Ниже квинтиля на ${Math.round(Math.abs(diff))} баллов`;
      badge = `<span class="maturity-gap-badge ${cls}" title="${title}"><i class="fa-solid fa-angles-up"></i> ${Math.abs(pct)}%</span>`;
    }
    el.innerHTML = `<span class="maturity-user-cell"><span class="maturity-user-score" style="color:${color}!important">${value}</span>${badge}</span>`;
  }
  function rawBenchmark(rowEl, col){
    if(!rowEl || !col || !rowEl.cells[col]) return null;
    return n(rowEl.cells[col].textContent);
  }
  function paintTable(score){
    const table = document.querySelector('.maturity-table');
    if(!table) return;
    const revenue = currentRevenue();
    const gaugeColor = colorForScore(score);
    table.style.setProperty('--maturity-color', gaugeColor);
    document.documentElement.style.setProperty('--maturity-color', gaugeColor);

    const yourSmall = table.querySelector('th.your-col small');
    if(yourSmall) yourSmall.textContent = `(${revenue.label})`;
    const revenueRow = table.querySelector('tr.revenue-row');
    if(revenueRow && revenueRow.cells[7]) revenueRow.cells[7].textContent = revenue.label;

    table.querySelectorAll('td,th').forEach(cell=>{
      cell.classList.remove('maturity-selected-col','maturity-your-selected','maturity-col-start','maturity-col-end');
      cell.style.outline=''; cell.style.outlineOffset=''; cell.style.boxShadow='';
      cell.style.borderLeftColor=''; cell.style.borderRightColor='';
      if(!cell.classList.contains('your-col')) cell.style.background='';
    });
    const yourCells = Array.from(table.querySelectorAll('th.your-col, tbody tr td:last-child'));
    yourCells.forEach((cell, idx)=>{
      cell.classList.add('maturity-your-selected');
      if(idx === 0) cell.classList.add('maturity-col-start');
      if(idx === yourCells.length - 1) cell.classList.add('maturity-col-end');
      cell.style.background = rgba(gaugeColor,.14);
      cell.style.borderLeftColor = gaugeColor;
      cell.style.borderRightColor = gaugeColor;
    });
    if(revenue.col){
      const selectedCells = [];
      table.querySelectorAll('tr').forEach(tr=>{
        const isLevelHeaderRow = tr.parentElement && tr.parentElement.tagName === 'THEAD' && tr.cells.length === 6;
        const targetIndex = isLevelHeaderRow ? revenue.col - 1 : revenue.col;
        const cell = tr.cells && tr.cells[targetIndex];
        if(!cell) return;
        selectedCells.push(cell);
      });
      selectedCells.forEach((cell, idx)=>{
        cell.classList.add('maturity-selected-col');
        if(idx === 0) cell.classList.add('maturity-col-start');
        if(idx === selectedCells.length - 1) cell.classList.add('maturity-col-end');
        cell.style.background = rgba(gaugeColor,.12);
        cell.style.borderLeftColor = gaugeColor;
        cell.style.borderRightColor = gaugeColor;
        cell.style.outline = '0';
        cell.style.outlineOffset = '0';
        cell.style.boxShadow = 'none';
      });
      if(revenueRow && revenueRow.cells[revenue.col]) revenueRow.cells[revenue.col].textContent = `${revenue.label} · выбранный квинтиль`;
    }

    DMQ_TABLE_ROWS.forEach(row=>{
      const userEl = document.getElementById(row.id);
      if(!userEl) return;
      const rowEl = userEl.closest('tr');
      const userValue = n(userEl.dataset.userScore) ?? n(userEl.textContent) ?? 0;
      const selectedBenchmark = rawBenchmark(rowEl, revenue.col);
      setUserCell(row.id, userValue, selectedBenchmark);
      for(let i=1;i<=6;i++){
        const c = rowEl && rowEl.cells[i];
        if(!c) continue;
        const bench = n(c.textContent);
        const diff = bench == null ? null : bench - userValue;
        c.style.color = diffColor(diff);
        c.style.fontWeight = '900';
        c.title = diff == null ? '' : `Квинтиль − ваша компания: ${Math.round(diff)} баллов`;
      }
    });
  }
  function updateTableFromCurrentAnswers(){
    if(typeof scores !== 'function' || typeof overall !== 'function') return;
    const s = scores();
    const score = typeof dmqScore100 === 'function' ? dmqScore100(overall(s)) : Math.round((overall(s)||0)/5*100);
    const revenue = currentRevenue();
    const table = document.querySelector('.maturity-table');
    if(!table) return;
    const vals = {
      tblStrategy: score100(s.strategy),
      tblData: score100(s.data),
      tblProcess: score100(s.process),
      tblCompetence: score100(s.competence),
      tblTech: score100(s.tech),
      tblIndex: score
    };
    Object.entries(vals).forEach(([id,val])=>{
      const el = document.getElementById(id);
      if(el){ el.dataset.userScore = String(val); el.textContent = String(val); }
    });
    paintTable(score);
  }
  const prevUpdateAll = window.updateAll || (typeof updateAll === 'function' ? updateAll : null);
  if(prevUpdateAll){
    window.updateAll = updateAll = function(){
      const result = prevUpdateAll.apply(this, arguments);
      updateTableFromCurrentAnswers();
      return result;
    };
  }
  document.addEventListener('input', function(e){
    if(e.target && e.target.matches('#coreQuestions input[type="range"], [name="revenue"]')) setTimeout(updateTableFromCurrentAnswers, 0);
  }, true);
  document.addEventListener('change', function(e){
    if(e.target && e.target.matches('#coreQuestions input[type="range"], [name="revenue"], #industry')) setTimeout(updateTableFromCurrentAnswers, 0);
  }, true);
  if(document.readyState === 'loading') document.addEventListener('DOMContentLoaded', updateTableFromCurrentAnswers);
  else updateTableFromCurrentAnswers();
})();


