/* final patch: color maturity level names by their own level values and keep selected header aligned */
(function(){
  function num(x){
    const v = Number(String(x == null ? '' : x).replace(',', '.').replace(/[^0-9.-]/g,''));
    return Number.isFinite(v) ? v : null;
  }
  function fallbackColor(score){
    if(typeof v28ScoreColor === 'function') return v28ScoreColor(score);
    if(typeof maturityColor === 'function') return maturityColor(score);
    if(score < 25) return '#d71920';
    if(score < 45) return '#f36f21';
    if(score < 65) return '#ffd23f';
    return '#1eb43f';
  }
  function colorLevelHeaders(){
    const table = document.querySelector('.maturity-table');
    if(!table || !table.tHead || table.tHead.rows.length < 2) return;
    const headerRow = table.tHead.rows[1];
    const indexRow = table.querySelector('tr.index-row');
    for(let i=0;i<6;i++){
      const th = headerRow.cells[i];
      if(!th) continue;
      const scoreCell = indexRow && indexRow.cells[i+1];
      const score = num(scoreCell ? scoreCell.textContent : null);
      const color = fallbackColor(score == null ? i*18 : score);
      th.style.setProperty('color', color, 'important');
      th.style.setProperty('borderBottomColor', color, 'important');
      th.style.setProperty('boxShadow', `inset 0 -3px 0 ${color}`);
    }
  }
  const prevUpdateAll = window.updateAll || null;
  if(prevUpdateAll){
    window.updateAll = updateAll = function(){
      const result = prevUpdateAll.apply(this, arguments);
      setTimeout(colorLevelHeaders, 0);
      return result;
    };
  }
  document.addEventListener('DOMContentLoaded', colorLevelHeaders);
  document.addEventListener('input', function(e){ if(e.target && e.target.matches('#coreQuestions input[type="range"], [name="revenue"]')) setTimeout(colorLevelHeaders, 0); }, true);
  document.addEventListener('change', function(e){ if(e.target && e.target.matches('#coreQuestions input[type="range"], [name="revenue"], #industry')) setTimeout(colorLevelHeaders, 0); }, true);
  colorLevelHeaders();
})();


