(function(){
  const DMQ_MATURITY_DOMAIN_ICONS = {
    tblStrategy: {label:'Стратегия и управление', icon:'fa-chess', color:'#35b653', attrs:'data-fa-requested="chess-board"'},
    tblData: {label:'Данные', icon:'fa-database', color:'#00a651'},
    tblProcess: {label:'Процессы', icon:'fa-diagram-project', color:'#ff6a00'},
    tblCompetence: {label:'Люди и культура', icon:'fa-users', color:'#35b653'},
    tblTech: {label:'Технологии', icon:'fa-microchip', color:'#ffb000'}
  };

  function renderDomainCell(cell, cfg){
    if(!cell || !cfg) return;
    const attrs = cfg.attrs ? ' ' + cfg.attrs : '';
    cell.innerHTML = `<span class="maturity-domain-mini"><span class="maturity-domain-mini-icon" style="color:${cfg.color}"><i class="fa-solid ${cfg.icon}"${attrs}></i></span><span class="maturity-domain-mini-text">${cfg.label}</span></span>`;
  }

  function applyMiniDomainIcons(){
    const table = document.querySelector('.maturity-table');
    if(!table) return;

    Object.keys(DMQ_MATURITY_DOMAIN_ICONS).forEach(id => {
      const userCell = document.getElementById(id);
      const row = userCell ? userCell.closest('tr') : null;
      const firstCell = row && row.cells ? row.cells[0] : null;
      renderDomainCell(firstCell, DMQ_MATURITY_DOMAIN_ICONS[id]);
    });
  }

  document.addEventListener('DOMContentLoaded', applyMiniDomainIcons);
  window.addEventListener('load', applyMiniDomainIcons);

  document.addEventListener('DOMContentLoaded', function(){
    const table = document.querySelector('.maturity-table');
    if(!table || !window.MutationObserver) return;
    const mo = new MutationObserver(function(){
      mo.disconnect();
      applyMiniDomainIcons();
      mo.observe(table, {childList:true, subtree:true, characterData:true});
    });
    mo.observe(table, {childList:true, subtree:true, characterData:true});
  });

  window.applyMiniDomainIcons = applyMiniDomainIcons;
})();


// --- extracted script block ---


(function(){
  function dmqGetCurrentStep(){
    var active=document.querySelector('.form-section.active[data-section]');
    var n=active ? Number(active.getAttribute('data-section')) : 0;
    return Number.isFinite(n) ? n : 0;
  }
  function dmqBuildStepContent(step){
    try{ if(step===1 && typeof window.buildDepartments==='function') window.buildDepartments(); }catch(e){}
    try{ if(step===2 && typeof window.buildCore==='function') window.buildCore(); }catch(e){}
    try{ if(typeof window.updateAll==='function') window.updateAll(); }catch(e){}
    try{ if(typeof window.applyMiniDomainIcons==='function') window.applyMiniDomainIcons(); }catch(e){}
  }
  window.dmqSetStepSafe = function(n){
    var step=Math.max(0, Math.min(3, Number(n)||0));
    window.step = step;
    document.querySelectorAll('.form-section[data-section]').forEach(function(section){
      section.classList.toggle('active', Number(section.getAttribute('data-section'))===step);
    });
    document.querySelectorAll('.step-btn[data-step]').forEach(function(btn){
      btn.classList.toggle('active', Number(btn.getAttribute('data-step'))===step);
    });
    dmqBuildStepContent(step);
    var diagnostic=document.getElementById('diagnostic');
    if(diagnostic) diagnostic.scrollIntoView({behavior:'smooth', block:'start'});
  };
  function bindTabs(){
    document.querySelectorAll('.step-btn[data-step]').forEach(function(btn){
      btn.onclick=function(e){ e.preventDefault(); window.dmqSetStepSafe(btn.getAttribute('data-step')); };
    });
    document.querySelectorAll('.next').forEach(function(btn){
      btn.onclick=function(e){ e.preventDefault(); window.dmqSetStepSafe(dmqGetCurrentStep()+1); };
    });
    document.querySelectorAll('.prev').forEach(function(btn){
      btn.onclick=function(e){ e.preventDefault(); window.dmqSetStepSafe(dmqGetCurrentStep()-1); };
    });
  }
  document.addEventListener('DOMContentLoaded', bindTabs);
  window.addEventListener('load', bindTabs);
  setTimeout(bindTabs, 0);
})();


