(function(){
  function sendHeight(){
    var h=Math.max(document.documentElement.scrollHeight, document.body.scrollHeight, 900);
    parent.postMessage({type:'dmqTildaHeight',height:h}, '*');
  }
  window.addEventListener('load', function(){ sendHeight(); setTimeout(sendHeight,300); setTimeout(sendHeight,1000); });
  window.addEventListener('resize', sendHeight);
  document.addEventListener('click', function(){ setTimeout(sendHeight,150); setTimeout(sendHeight,600); });
  document.addEventListener('input', function(){ setTimeout(sendHeight,150); });
})();


